import{_ as e,o as t,c as o,a}from"./app.c5171353.js";const k=JSON.parse('{"title":"1machinemaker1 v. 14uu, Aug 2017","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/1machinemaker1_v_14uu_aug_2017.md","lastUpdated":1666023928000}'),r={name:"government/court-cases-precedents/1machinemaker1_v_14uu_aug_2017.md"},i=a('<h1 id="_1machinemaker1-v-14uu-aug-2017" tabindex="-1">1machinemaker1 v. 14uu, Aug 2017 <a class="header-anchor" href="#_1machinemaker1-v-14uu-aug-2017" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With ArowShot presiding, on 1st October 2017, without any official charges ordered 1machinemaker1 and 14uu to return the other&#39;s items, though 14uu has to do so first. In addition, 14uu is sentenced to 3 days &quot;probation&quot; or until 1machinemaker1 gives consent to be freed, whichever is sooner.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>ArowShot</strong>:</p><blockquote><p>Let&#39;s go</p><p>Both of you explain what happened</p></blockquote><p><strong>14uu</strong>:</p><blockquote><p>i gib his stuff back<br> he kills me</p><blockquote><p>i ask for my stuff back</p></blockquote></blockquote><p><strong>ArowShot</strong>:</p><blockquote><p>14 you go first The whole story</p></blockquote><p><strong>14uu</strong>:</p><blockquote><p>he dont give<br> i trie to kill him for him to give my stuff back</p><blockquote><p>lets imprison 14<br> take itens from a public chest</p></blockquote><p>cause it looks like public stuff</p><blockquote><p>find out that its machine&#39;s<br> gives 2 hits with a d sword for fun which kill not even an unarmored<br> he tries to kill me</p></blockquote><p>&gt;i fight back</p><blockquote><p>i run<br> i die</p></blockquote><p>&gt;i lose my stuff</p><blockquote><p>he gives only some of it back<br> i ask for the rest<br> he still dont give all</p></blockquote><p>&gt;i trie to kill him<br> &gt;die again</p></blockquote><blockquote><blockquote><p>he pearls me then relase keeping ALL my stuff<br> i blow him up to get my stuff<br> he wasnt with it<br> i store his stuff to be fair<br> safe logout<br> login back<br> get pearled<br> end</p></blockquote></blockquote><p><strong>ArowShot</strong>:</p><blockquote><p>Okay 1machinemaker1 what&#39;s your side of the story</p></blockquote><p><strong>1machinemaker1</strong>:</p><blockquote><p>okay, my version: 14 takes six stacks of iron and a stack of obby from a chest at the obby grinder, i say stuff about it, this is fine</p></blockquote><p><strong>14uu</strong>:</p><blockquote><p>5 stacks<br> not 6</p></blockquote><p><strong>1machinemaker1</strong>:</p><blockquote><p>five, sure<br> i don&#39;t recall exactly<br> but yeah we established five after that<br> anyway, we meet, he shows up with full dia + dia sword, starts attacking me<br> i attack back and kill him<br> he had a pearl on him, and said he was trying to pearl me later, for lols<br> at this point i try to pearl him for committing a crime and hold him, but free his pearl because right clicking<br> i then keep his stuff for the same reason, him comitting a crime<br> he then kills me while i afk<br> this is really f*****g stupid<br> 14 please stop s**tstirring<br> i didn&#39;t even want to take this to trial, just wanted to negotiate, and holding things is a common practice when one has committed a crime</p></blockquote><p><strong>ArowShot</strong>:</p><blockquote><p>Okay well I have enough to decide, here&#39;s the sentence: Both of you give each other stuff back, 14 goes first, then 14 you&#39;ll go on probation for 3 days or until machine says you can be free</p></blockquote><p><strong>1machinemaker1</strong>:</p><blockquote><p>sounds great<br> what&#39;s probation</p></blockquote><p><strong>ArowShot</strong>:</p><blockquote><p>pearled and summoned<br> and no attacking people<br> probation will also be put on hold in the event of conflict where it is necessary for 14 to fight</p></blockquote>',27),s=[i];function n(c,h,l,u,p,b){return t(),o("div",null,s)}const g=e(r,[["render",n]]);export{k as __pageData,g as default};
